import React, { useState, useRef, useCallback } from 'react';
import axios from 'axios';

// ─── SVG Circular Progress Ring ───────────────────────────────────────────────
// size: ring diameter in px | status: queued|uploading|processing|completed|failed
function CircleRing({ status }) {
  const r  = 16;          // radius
  const cx = 20;          // center
  const stroke = 3;
  const circ = 2 * Math.PI * r; // circumference ≈ 100.5

  const map = {
    queued:     { dash: 0,     color: '#3a3a5c', spin: false, icon: null },
    uploading:  { dash: circ * 0.4, color: '#43e5f7', spin: true,  icon: null },
    processing: { dash: circ * 0.65, color: '#6c63ff', spin: true,  icon: null },
    completed:  { dash: circ,  color: '#1db954', spin: false, icon: '✓' },
    failed:     { dash: circ,  color: '#e74c5e', spin: false, icon: '✕' },
  };
  const cfg = map[status] || map.queued;

  return (
    <svg width="40" height="40" viewBox="0 0 40 40" className="ring-svg">
      {/* background track */}
      <circle cx={cx} cy={cx} r={r} fill="none" stroke="#1c1c3a" strokeWidth={stroke} />
      {/* progress arc */}
      <circle
        cx={cx} cy={cx} r={r}
        fill="none"
        stroke={cfg.color}
        strokeWidth={stroke}
        strokeLinecap="round"
        strokeDasharray={`${cfg.dash} ${circ}`}
        strokeDashoffset={0}
        transform={`rotate(-90 ${cx} ${cx})`}
        className={cfg.spin ? 'ring-spin' : ''}
        style={{ transition: 'stroke-dasharray 0.5s ease' }}
      />
      {/* centre icon */}
      {cfg.icon && (
        <text
          x={cx} y={cx + 5}
          textAnchor="middle"
          fontSize="11"
          fontWeight="700"
          fill={cfg.color}
        >
          {cfg.icon}
        </text>
      )}
    </svg>
  );
}

// ─── Helpers ──────────────────────────────────────────────────────────────────
const fmtBytes = b => {
  if (!b) return '0 B';
  const k = 1024, u = ['B','KB','MB','GB'];
  const i = Math.floor(Math.log(b) / Math.log(k));
  return `${(b / Math.pow(k, i)).toFixed(1)} ${u[i]}`;
};
const uid = () => Math.random().toString(36).slice(2);

const STATUS_LABEL = {
  queued:     'Queued',
  uploading:  'Uploading…',
  processing: 'Converting…',
  completed:  'Done',
  failed:     'Failed',
};

const ROW_FILL_BY_STATUS = {
  queued: '0%',
  uploading: '35%',
  processing: '70%',
  completed: '100%',
  failed: '0%',
};

// ─────────────────────────────────────────────────────────────────────────────
export default function App() {
  const inputRef = useRef(null);
  const [files, setFiles]               = useState([]);
  const [uploadPct, setUploadPct]       = useState(0);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [dragOver, setDragOver]         = useState(false);

  // YouTube Tab States
  const [activeTab, setActiveTab]       = useState('local');
  const [ytMode, setYtMode]             = useState('videos');
  const [ytUrls, setYtUrls]             = useState('');
  const [playlistUrl, setPlaylistUrl]   = useState('');
  const [playlistStart, setPlaylistStart] = useState(1);
  const [playlistEnd, setPlaylistEnd]   = useState(50);
  const [ytLoading, setYtLoading]       = useState(false);

  const total     = files.length;
  const completed = files.filter(f => f.status === 'completed').length;
  const failed    = files.filter(f => f.status === 'failed').length;
  const progress  = total === 0 ? 0 : Math.round((completed + failed) / total * 100);

  // ── Add files ────────────────────────────────────────────────────────────
  const addFiles = useCallback(incoming => {
    const valid   = [...incoming].filter(f => f.name.toLowerCase().endsWith('.m4a'));
    const skipped = incoming.length - valid.length;
    if (skipped > 0) alert(`${skipped} file(s) skipped — only .m4a accepted.`);
    if (!valid.length) return;
    setFiles(prev => [
      ...prev,
      ...valid.map(f => ({ id: uid(), name: f.name, size: f.size,
                           status: 'queued', downloadUrl: null, error: null, _file: f })),
    ]);
  }, []);

  const onDrop = e => { e.preventDefault(); setDragOver(false); addFiles(e.dataTransfer.files); };
  const removeFile = id => { if (!isSubmitting) setFiles(p => p.filter(f => f.id !== id)); };
  const clearAll   = () => { if (!isSubmitting) { setFiles([]); setUploadPct(0); if (inputRef.current) inputRef.current.value = ''; } };

  // ── Convert ──────────────────────────────────────────────────────────────
  const handleConvert = async () => {
    const queued = files.filter(f => f.status === 'queued');
    if (!queued.length) return;

    setIsSubmitting(true);
    setUploadPct(0);
    setFiles(p => p.map(f => f.status === 'queued' ? { ...f, status: 'uploading' } : f));

    const form = new FormData();
    queued.forEach(f => form.append('files', f._file));

    try {
      await axios.post('/convert', form, {
        headers: { 'Content-Type': 'multipart/form-data' },
        onUploadProgress: e => {
          const pct = e.total ? Math.round(e.loaded / e.total * 100) : 0;
          setUploadPct(pct);
          if (pct === 100)
            setFiles(p => p.map(f => f.status === 'uploading' ? { ...f, status: 'processing' } : f));
        },
      });

      // Upload finished, server has queued them. Now start polling for status.
      pollStatus();

    } catch (err) {
      const msg = err.response?.data?.error || err.message;
      setFiles(p => p.map(f =>
        ['uploading','processing'].includes(f.status)
          ? { ...f, status: 'failed', error: msg } : f
      ));
      setIsSubmitting(false);
    }
  };

  const pollStatus = async () => {
    try {
      const { data } = await axios.get('/conversions');

      setFiles(prev => {
        let stillProcessing = false;
        const updated = prev.map(localFile => {
          // Completed/failed rows are terminal states.
          if (['completed', 'failed'].includes(localFile.status)) return localFile;

          // Local queued files (with a browser File object) are not submitted yet.
          if (localFile.status === 'queued' && localFile._file) return localFile;

          // Find the newest matching record for this filename
          const match = data.conversions.find(r => r.original_name === localFile.name);
          if (!match) {
            if (['uploading', 'processing'].includes(localFile.status)) stillProcessing = true;
            return localFile;
          }

          if (['pending', 'processing'].includes(match.status)) {
            stillProcessing = true;
            return { ...localFile, status: 'processing' };
          }

          // Otherwise, it finished or failed!
          return { 
            ...localFile, 
            status: match.status,
            downloadUrl: match.download_url || null, 
            error: match.error || null 
          };
        });

        // Loop polling if any file is still converting
        if (stillProcessing) {
          setTimeout(pollStatus, 2000);
        } else {
          setIsSubmitting(false);
        }

        return updated;
      });
    } catch (err) {
      console.error('Polling error', err);
      setTimeout(pollStatus, 5000); // retry gracefully
    }
  };

  const queueYoutubeItems = (initialStates) => {
    const newItems = initialStates.map(f => ({
      id: f.id,
      name: f.file,
      size: 0,
      status: 'queued',
      downloadUrl: null,
      error: null,
      _file: null
    }));

    setFiles(prev => [...prev, ...newItems]);
    pollStatus();
  };

  const handleYoutubeVideosSubmit = async () => {
    const lines = ytUrls.split('\n').map(s => s.trim()).filter(s => s.startsWith('http'));
    if (!lines.length) return alert('Please paste at least one valid YouTube URL.');
    if (lines.length > 50) return alert('Please queue at most 50 links at once.');
    setYtLoading(true);

    try {
      const { data } = await axios.post('/youtube-videos', { urls: lines });
      queueYoutubeItems(data.initialStates || []);
      setYtUrls('');
    } catch (err) {
      alert(err.response?.data?.error || err.message);
    } finally {
      setYtLoading(false);
    }
  };

  const handleYoutubePlaylistSubmit = async () => {
    const start = Number(playlistStart);
    const end = Number(playlistEnd);

    if (!playlistUrl.includes('list=')) {
      return alert('Please paste a valid YouTube playlist URL containing list=...');
    }
    if (!Number.isInteger(start) || !Number.isInteger(end) || start < 1 || end < 1 || end < start) {
      return alert('Please enter a valid start/end range. Example: 1 to 50');
    }
    if (end - start + 1 > 50) {
      return alert('Max 50 videos per batch. Use ranges like 1-50, then 51-100.');
    }

    setYtLoading(true);
    try {
      const { data } = await axios.post('/youtube-playlist', {
        playlistUrl: playlistUrl.trim(),
        start,
        end,
      });
      queueYoutubeItems(data.initialStates || []);
    } catch (err) {
      alert(err.response?.data?.error || err.message);
    } finally {
      setYtLoading(false);
    }
  };

  const handleYoutubeSubmit = async (e) => {
    e.preventDefault();
    if (ytMode === 'playlist') {
      await handleYoutubePlaylistSubmit();
      return;
    }
    await handleYoutubeVideosSubmit();
  };

  // ── Download programmatically to bypass CRA SPA fallback ─────────────────
  const handleDownload = async (url, filename) => {
    try {
      const res = await fetch(url);
      const blob = await res.blob();
      const blobUrl = window.URL.createObjectURL(blob);
      const tempLink = document.createElement('a');
      tempLink.href = blobUrl;
      // Re-add .mp3 extension for the user's downloaded file
      const baseName = filename.replace(/\.m4a$/i, '');
      tempLink.setAttribute('download', `${baseName}.mp3`);
      document.body.appendChild(tempLink);
      tempLink.click();
      document.body.removeChild(tempLink);
      window.URL.revokeObjectURL(blobUrl);
    } catch (err) {
      alert('Download failed. Server might be down.');
    }
  };

  const handleDownloadZip = () => {
    const completedIds = files.filter(f => f.status === 'completed' && f.downloadUrl !== null).map(f => f.id);
    if (!completedIds.length) return;

    // Use a native browser navigation to the download endpoint so the browser handles 
    // the heavy streaming and displays a native progress bar for the ZIP.
    const url = `/download-zip?ids=${completedIds.join(',')}`;

    // Create an invisible iframe/link to trigger the download without leaving the page
    const link = document.createElement('a');
    link.href = url;
    link.download = `AudioBatch-${Date.now()}.zip`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  // ─────────────────────────────────────────────────────────────────────────
  return (
    <div className="app">
      {/* Header */}
      <header className="header">
        <div className="logo">
          <span className="logo-icon">🎵</span>
          <div>
            <h1>M4A → MP3</h1>
            <p>Professional batch audio converter</p>
          </div>
        </div>
        <div className="header-stats">
          <span className="stat"><b>{total}</b> items</span>
          <span className="stat s-done"><b>{completed}</b> done</span>
          {failed > 0 && <span className="stat s-fail"><b>{failed}</b> failed</span>}
        </div>
      </header>

      {/* Tabs */}
      <div className="tabs" style={{ display: 'flex', gap: '10px', marginBottom: '20px' }}>
        <button className={`btn ${activeTab === 'local' ? 'btn-primary' : 'btn-ghost'}`} 
                onClick={() => setActiveTab('local')}>📂 Local .M4A Files</button>
        <button className={`btn ${activeTab === 'youtube' ? 'btn-primary' : 'btn-ghost'}`} 
                onClick={() => setActiveTab('youtube')} style={{ background: activeTab === 'youtube' ? '#ff0000' : '' }}>▶️ YouTube Playlist</button>
      </div>

      {activeTab === 'local' ? (
        <div
          className={`drop-zone ${dragOver ? 'active' : ''}`}
          onClick={() => !isSubmitting && inputRef.current.click()}
          onDragOver={e => { e.preventDefault(); setDragOver(true); }}
          onDragLeave={() => setDragOver(false)}
          onDrop={onDrop}
        >
          <div className="drop-icon">📂</div>
          <p className="drop-title">Drop your .m4a files here</p>
          <p className="drop-sub">or click to browse — up to 50 files, 300 MB each</p>
          <input ref={inputRef} type="file" multiple accept=".m4a"
                 style={{ display:'none' }} onChange={e => addFiles(e.target.files)} />
        </div>
      ) : (
        <form className="drop-zone" style={{ cursor: 'default', display: 'flex', flexDirection: 'column', gap: '14px' }} onSubmit={handleYoutubeSubmit}>
           <h3 style={{ margin: 0, color: '#fff' }}>🎬 YouTube → MP3 Converter</h3>
           <div style={{ display: 'flex', gap: '10px', justifyContent: 'center', flexWrap: 'wrap' }}>
             <button
               type="button"
               className={`btn ${ytMode === 'videos' ? 'btn-primary' : 'btn-ghost'}`}
               onClick={() => setYtMode('videos')}
               disabled={ytLoading}
             >
               Video Links
             </button>
             <button
               type="button"
               className={`btn ${ytMode === 'playlist' ? 'btn-primary' : 'btn-ghost'}`}
               onClick={() => setYtMode('playlist')}
               disabled={ytLoading}
             >
               Playlist Range
             </button>
           </div>
           <p style={{ margin: 0, color: 'var(--text-muted)', fontSize: '0.85rem' }}>
             {ytMode === 'playlist'
               ? 'Paste a playlist URL and choose a range. Limit: max 50 items per batch (1-50, then 51-100, etc).'
               : 'Paste one YouTube video URL per line. The server will download each one and convert it to MP3.'}
           </p>
           {ytMode === 'playlist' ? (
             <>
               <input
                 type="text"
                 value={playlistUrl}
                 onChange={e => setPlaylistUrl(e.target.value)}
                 placeholder="https://www.youtube.com/playlist?list=..."
                 required
                 style={{ width: '100%', boxSizing: 'border-box', padding: '12px', borderRadius: '8px', background: 'rgba(255,255,255,0.05)', border: '1px solid rgba(255,255,255,0.15)', color: '#fff', fontSize: '0.9rem' }}
               />
               <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '10px', width: '100%' }}>
                 <input
                   type="number"
                   min="1"
                   value={playlistStart}
                   onChange={e => setPlaylistStart(e.target.value)}
                   required
                   style={{ width: '100%', boxSizing: 'border-box', padding: '12px', borderRadius: '8px', background: 'rgba(255,255,255,0.05)', border: '1px solid rgba(255,255,255,0.15)', color: '#fff' }}
                 />
                 <input
                   type="number"
                   min="1"
                   value={playlistEnd}
                   onChange={e => setPlaylistEnd(e.target.value)}
                   required
                   style={{ width: '100%', boxSizing: 'border-box', padding: '12px', borderRadius: '8px', background: 'rgba(255,255,255,0.05)', border: '1px solid rgba(255,255,255,0.15)', color: '#fff' }}
                 />
               </div>
             </>
           ) : (
             <textarea
               value={ytUrls}
               onChange={e => setYtUrls(e.target.value)}
               placeholder={`https://www.youtube.com/watch?v=XXXX\nhttps://www.youtube.com/watch?v=YYYY\nhttps://www.youtube.com/watch?v=ZZZZ`}
               required
               rows={6}
               style={{ width: '100%', boxSizing: 'border-box', padding: '12px', borderRadius: '8px', background: 'rgba(255,255,255,0.05)', border: '1px solid rgba(255,255,255,0.15)', color: '#fff', fontFamily: 'monospace', fontSize: '0.82rem', resize: 'vertical' }}
             />
           )}
           <p style={{ margin: 0, color: 'var(--text-muted)', fontSize: '0.8rem' }}>
             {ytMode === 'playlist'
               ? '💡 Tip: Queue in chunks: 1-50, then 51-100, then 101-150.'
               : '💡 Tip: Paste up to 50 links per queue. Find individual video links on YouTube by right-clicking a video and choosing "Copy video URL".'}
           </p>
           <button type="submit" className="btn btn-primary" style={{ background: 'linear-gradient(135deg, #ff0000, #cc0000)', width: 'fit-content', margin: '0 auto' }} disabled={ytLoading}>
             {ytLoading ? '⏳ Queuing...' : '⬇ Queue & Convert to MP3'}
           </button>
        </form>
      )}

      {/* Buttons */}
      {total > 0 && (
        <div className="action-bar">
          <button className="btn btn-primary" onClick={handleConvert}
                  disabled={isSubmitting || !files.some(f => f.status === 'queued')}>
            {isSubmitting ? 'Converting…' : `Convert ${files.filter(f=>f.status==='queued').length} file(s)`}
          </button>
          {completed > 0 && (
            <button className="btn" style={{ background: '#1db954', color: '#fff', marginLeft: '10px' }} 
                    onClick={handleDownloadZip} disabled={isSubmitting}>
              📦 Download {completed} as ZIP
            </button>
          )}
          <button className="btn btn-ghost" onClick={clearAll} disabled={isSubmitting}>Clear All</button>
        </div>
      )}

      {/* Upload progress bar */}
      {isSubmitting && (
        <div className="progress-wrap">
          <div className="progress-labels"><span>Uploading to server…</span><span>{uploadPct}%</span></div>
          <div className="progress-track">
            <div className="progress-fill upload-fill" style={{ width: `${uploadPct}%` }} />
          </div>
        </div>
      )}

      {/* Overall progress bar */}
      {total > 0 && (
        <div className="progress-wrap">
          <div className="progress-labels">
            <span>Overall conversion</span>
            <span>{completed + failed} / {total}</span>
          </div>
          <div className="progress-track">
            <div className="progress-fill" style={{
              width: `${progress}%`,
              background: failed > 0
                ? 'linear-gradient(90deg,#6c63ff,#e74c5e)'
                : 'linear-gradient(90deg,#6c63ff,#43e5f7)',
            }} />
          </div>
        </div>
      )}

      {/* File table */}
      {total > 0 && (
        <div className="table-wrap">
          <table className="file-table">
            <thead>
              <tr>
                <th style={{width:52}}>#</th>
                <th style={{width:44}}>⬤</th>
                <th>File Name</th>
                <th style={{width:80}}>Size</th>
                <th style={{width:110}}>Status</th>
                <th style={{width:110}}>Action</th>
              </tr>
            </thead>
            <tbody>
              {files.map((f, i) => (
                <tr
                  key={f.id}
                  className={`row-progress ${f.status === 'completed' ? 'row-done' : ''} ${f.status === 'failed' ? 'row-fail' : ''} ${f.status === 'processing' ? 'row-processing' : ''}`.trim()}
                  style={{ '--row-fill': ROW_FILL_BY_STATUS[f.status] || '0%' }}
                >
                  <td className="td-num">{i + 1}</td>
                  <td className="td-ring"><CircleRing status={f.status} /></td>
                  <td className="td-name" title={f.name}>
                    <div>{f.name}{f.error && <span className="err-tip" title={f.error}> ⚠</span>}</div>
                    {f.status === 'failed' && f.error && (
                      <div style={{ marginTop: '4px', color: '#ff9aa5', fontSize: '0.75rem', whiteSpace: 'normal' }}>
                        {f.error}
                      </div>
                    )}
                  </td>
                  <td className="td-size">{fmtBytes(f.size)}</td>
                  <td>
                    <span className={`chip chip-${f.status}`}>
                      {STATUS_LABEL[f.status] || f.status}
                    </span>
                  </td>
                  <td>
                    {f.status === 'completed' && f.downloadUrl
                      ? <button className="btn btn-sm btn-download" onClick={() => handleDownload(f.downloadUrl, f.name)}>⬇ Download</button>
                      : f.status === 'queued'
                      ? <button className="btn btn-sm btn-remove" onClick={() => removeFile(f.id)}>✕ Remove</button>
                      : '—'}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {total === 0 && (
        <div className="empty-state">
          <p>No files selected yet. Add some .m4a files to get started.</p>
        </div>
      )}

      <footer className="footer">
        Converted files are automatically deleted after 1 hour &nbsp;·&nbsp; Max 50 files per batch
      </footer>
    </div>
  );
}
